    10→namespace sofa {
    11→namespace pbrpc {
    12→
    13→class EventHandlerImp : public RpcChannel::EventHandler
    14→{
    15→public:
    16→    EventHandlerImp(::sofa::pbrpc::weak_ptr<DynamicRpcChannelImpl> channel) : _channel(channel) {}
    17→    virtual ~EventHandlerImp() {}
    18→    virtual void OnAddressAdded(const std::vector<std::string>& address_list)
    19→    {
    20→        ::sofa::pbrpc::shared_ptr<DynamicRpcChannelImpl> channel = _channel.lock();
    21→        if (channel) {
    22→            channel->OnAddressAdded(address_list);
    23→        }
    24→    }
    25→    virtual void OnAddressRemoved(const std::vector<std::string>& address_list)
    26→    {
    27→        ::sofa::pbrpc::shared_ptr<DynamicRpcChannelImpl> channel = _channel.lock();
    28→        if (channel) {
    29→            channel->OnAddressRemoved(address_list);
    30→        }
    31→    }
    32→private:
    33→    ::sofa::pbrpc::weak_ptr<DynamicRpcChannelImpl> _channel;
    34→};
    35→
    36→DynamicRpcChannelImpl::DynamicRpcChannelImpl(
    37→        const RpcClientImplPtr& client_impl,
    38→        ::sofa::pbrpc::RpcChannel::AddressProvider* address_provider,
    39→        const RpcChannelOptions& options)
    40→    : _client_impl(client_impl)
    41→    , _address_provider(address_provider)
    42→    , _options(options)
    43→    , _timer_id(0)
    44→    , _is_detect_disabled(false)
    45→{
    46→    _address_provider->GetInitAddress(&_init_address_list);
    47→}
    48→
    49→DynamicRpcChannelImpl::DynamicRpcChannelImpl(
    50→        const RpcClientImplPtr& client_impl,
    51→        const std::vector<std::string>& address_list,
    52→        const RpcChannelOptions& options)
    53→    : _client_impl(client_impl)
    54→    , _address_provider(NULL)
    55→    , _init_address_list(address_list)
    56→    , _options(options)
    57→    , _timer_id(0)
    58→    , _is_detect_disabled(false)
    59→{
    60→}
    61→
    62→DynamicRpcChannelImpl::~DynamicRpcChannelImpl()
    63→{
    64→}
    65→
    66→bool DynamicRpcChannelImpl::Init()
    67→{
    68→    // add init addresses
    69→    OnAddressAdded(_init_address_list);
    70→
    71→    // register event handler
    72→    if (_address_provider) {
    73→        _address_provider->RegisterEventHandler(new EventHandlerImp(shared_from_this()));
    74→    }
    75→
    76→    // register TimerDetect
    77→    _timeout_manager.reset(new TimeoutManager());
    78→    _timer_id = _timeout_manager->add_repeating(kDetectInterval,
    79→            ::sofa::pbrpc::NewPermanentExtClosure(shared_from_this(),
    80→                &DynamicRpcChannelImpl::TimerDetect));
    81→
    82→#if defined( LOG )
    83→    LOG(INFO) << "Init(): init address count: " << _added_set.size();
    84→#else
    85→    SLOG(INFO, "Init(): init address count: %u", _added_set.size());
    86→#endif
    87→    return true;
    88→}
    89→
    90→void DynamicRpcChannelImpl::Stop()
    91→{
    92→    // remove TimerDetect
    93→    _timeout_manager->erase(_timer_id);
    94→    {
    95→        ScopedLocker<LockType> _(_detect_lock);
    96→        _is_detect_disabled = true;
    97→    }
    98→    _timeout_manager.reset();
    99→
   100→    // clear SimpleRpcChannelImpl
   101→    {
   102→        ScopedLocker<LockType> _1(_add_remove_lock);
   103→        ScopedLocker<LockType> _2(_map_lock);
   104→        for (ServerContextMap::const_iterator it = _live_map.begin();
   105→                it != _live_map.end(); ++it) {
   106→            const ServerContextPtr& server = it->second;
   107→            if (server->is_channel_inited) {
   108→                server->channel->Stop();
   109→            }
   110→        }
   111→        for (ServerContextMap::const_iterator it = _unlive_map.begin();
   112→                it != _unlive_map.end(); ++it) {
   113→            const ServerContextPtr& server = it->second;
   114→            if (server->is_channel_inited) {
   115→                server->channel->Stop();
   116→            }
   117→        }
   118→        _live_map.clear();
   119→        _unlive_map.clear();
   120→    }
   121→
   122→#if defined( LOG )
   123→    LOG(INFO) << "Stop(): dynamic rpc channel stopped";
   124→#else
   125→    SLOG(INFO, "Stop(): dynamic rpc channel stopped");
   126→#endif
   127→}
   128→
   129→void DynamicRpcChannelImpl::CallMethod(
   130→        const ::google::protobuf::MethodDescriptor* method,
   131→        ::google::protobuf::RpcController* controller,
   132→        const ::google::protobuf::Message* request,
   133→        ::google::protobuf::Message* response,
   134→        ::google::protobuf::Closure* done)
   135→{
   136→    ++_wait_count;
   137→
   138→    // prepare controller
   139→    RpcController* sofa_controller = dynamic_cast<RpcController*>(controller);
   140→    SCHECK(sofa_controller != NULL); // should be sofa::pbrpc::RpcController
   141→    RpcControllerImplPtr cntl = sofa_controller->impl();
   142→
   143→    // Choose an server.
   144→    // If the server's channel is not created, then create it first.
   145→    ServerContextPtr server;
   146→    RpcErrorCode choose_ret;
   147→    int retry_count = 0;
   148→    while (true) {
   149→        choose_ret = ChooseServer(server, retry_count + 1);
   150→        if (choose_ret == RPC_SUCCESS){
   151→            if (server->InitChannel(_client_impl, _options)) {
   152→                // init ok
   153→                break;
   154→            }
   155→            else  {
   156→#if defined( LOG )
   157→                LOG(ERROR) << "CallMethod(): init channel failed: ["
   158→                           << server->server_address << "]";
   159→#else
   160→                SLOG(ERROR, "CallMethod(): init channel failed: [%s]",
   161→                        server->server_address.c_str());
   162→#endif
   163→                MoveToUnlive(server->server_address, "init channel failed");
   164→                choose_ret = RPC_ERROR_SERVER_UNAVAILABLE;
   165→                server.reset();
   166→            }
   167→        }
   168→        // check retry count
   169→        if (retry_count >= kRetryCount) {
   170→            // retry out
   171→            server.reset();
   172→            break;
   173→        }
   174→        // sleep to retry
   175→        usleep(kRetryInterval * 1000);
   176→        ++retry_count;
   177→    }
   178→
   179→    // If no server available, callback with error.
   180→    if (!server) {
   181→#if defined( LOG )
   182→        LOG(ERROR) << "CallMethod(): choose server failed with retry_count="
   183→                   << retry_count << ": " << RpcErrorCodeToString(choose_ret);
   184→#else
   185→        SLOG(ERROR, "CallMethod(): choose server failed with retry_count=%d: %s",
   186→                retry_count, RpcErrorCodeToString(choose_ret));
   187→#endif
   188→        cntl->SetFailed(choose_ret, "choose server failed in dynamic channel");
   189→        CallDone(server, cntl);
   190→        if (done != NULL) {
   191→            _client_impl->GetCallbackThreadGroup()->post(done);
   192→        }
   193→        return;
   194→    }
   195→    SCHECK(server->channel);
   196→
   197→    // Call method.
   198→    if (done != NULL) {
   199→        // async call, replace callback with AsyncCallback
   200→        done = ::sofa::pbrpc::NewClosure(shared_from_this(),
   201→                &DynamicRpcChannelImpl::AsyncCallback, server, cntl, done);
   202→    }
   203→    server->last_request_seq = ++_request_count;
   204→    server->channel->CallMethod(method, controller, request, response, done);
   205→    if (done == NULL) {
   206→        // sync call
   207→        CallDone(server, cntl);
   208→    }
   209→}
   210→
   211→uint32 DynamicRpcChannelImpl::WaitCount()
   212→{
   213→    return _wait_count;
   214→}
   215→
   216→void DynamicRpcChannelImpl::OnAddressAdded(const std::vector<std::string>& address_list)
   217→{
   218→    ScopedLocker<LockType> _(_add_remove_lock);
   219→    // prepare
   220→    AddResultMap add_results;
   221→    for (std::vector<std::string>::const_iterator it = address_list.begin();
   222→            it != address_list.end(); ++it) {
   223→        std::string server_address = *it;
   224→        if (server_address.empty()) {
   225→            // ignore empty address
   226→            continue;
   227→        }
   228→        if (add_results.find(server_address) != add_results.end()) {
   229→            // duplicate address
   230→#if defined( LOG )
   231→            LOG(WARNING) << "OnAddressAdded(): duplicate address: [" << server_address << "]";
   232→#else
   233→            SLOG(WARNING, "OnAddressAdded(): duplicate address: [%s]", server_address.c_str());
   234→#endif
   235→            continue;
   236→        }
   237→        AddResult& result = add_results[server_address];
   238→        result.add_failed = false;
   239→        if (_added_set.find(server_address) != _added_set.end()) {
   240→            result.add_failed = true;
   241→            result.fail_reason = "already added";
   242→            continue;
   243→        }
   244→        result.server_context.reset(new ServerContext(server_address));
   245→    }
   246→    // add into _live_map
   247→    {
   248→        ScopedLocker<LockType> _(_map_lock);
   249→        for (AddResultMap::iterator it = add_results.begin();
   250→                it != add_results.end(); ++it) {
   251→            const std::string& server_address = it->first;
   252→            const AddResult& result = it->second;
   253→            if (!result.add_failed) {
   254→                _live_map[server_address] = result.server_context;
   255→                _added_set.insert(server_address);
   256→            }
   257→        }
   258→    }
   259→    // print log
   260→    for (AddResultMap::iterator it = add_results.begin();
   261→            it != add_results.end(); ++it) {
   262→        const std::string& server_address = it->first;
   263→        const AddResult& result = it->second;
   264→        if (!result.add_failed) {
   265→#if defined( LOG )
   266→            LOG(INFO) << "OnAddressAdded(): add address succeed: [" << server_address << "]";
   267→#else
   268→            SLOG(INFO, "OnAddressAdded(): add address succeed: [%s]", server_address.c_str());
   269→#endif
   270→        }
   271→        else {
   272→#if defined( LOG )
   273→            LOG(ERROR) << "OnAddressAdded(): add address failed: [" << server_address << "]"
   274→                       << result.fail_reason;
   275→#else
   276→            SLOG(ERROR, "OnAddressAdded(): add address failed: [%s]: %s",
   277→                    server_address.c_str(), result.fail_reason.c_str());
   278→#endif
   279→        }
   280→    }
   281→}
   282→
   283→void DynamicRpcChannelImpl::OnAddressRemoved(const std::vector<std::string>& address_list)
   284→{
   285→    ScopedLocker<LockType> _(_add_remove_lock);
   286→    // prepare
   287→    RemoveResultMap remove_results;
   288→    for (std::vector<std::string>::const_iterator it = address_list.begin();
   289→            it != address_list.end(); ++it) {
   290→        std::string server_address = *it;
   291→        if (server_address.empty()) {
   292→            // ignore empty address
   293→            continue;
   294→        }
   295→        if (remove_results.find(server_address) != remove_results.end()) {
   296→#if defined( LOG )
   297→            LOG(WARNING) << "OnAddressRemoved(): duplicate address: [" << server_address << "]";
   298→#else
   299→            SLOG(WARNING, "OnAddressRemoved(): duplicate address: [%s]", server_address.c_str());
   300→#endif
   301→            continue;
   302→        }
   303→        RemoveResult& result = remove_results[server_address];
   304→        result.remove_failed = false;
   305→        if (_added_set.find(server_address) == _added_set.end()) {
   306→            result.remove_failed = true;
   307→            result.fail_reason = "not exist";
   308→            continue;
   309→        }
   310→    }
   311→    // remove from _live_map or _unlive_map
   312→    {
   313→        ScopedLocker<LockType> _(_map_lock);
   314→        for (RemoveResultMap::iterator it = remove_results.begin();
   315→                it != remove_results.end(); ++it) {
   316→            const std::string& server_address = it->first;
   317→            const RemoveResult& result = it->second;
   318→            if (!result.remove_failed) {
   319→                ServerContextMap::iterator find = _live_map.find(server_address);
   320→                if (find != _live_map.end()) {
   321→                    // remove from _live_map
   322→                    find->second->is_removed = true;
   323→                    _live_map.erase(find);
   324→                }
   325→                else {
   326→                    // remove from _unlive_map
   327→                    find = _unlive_map.find(server_address);
   328→                    SCHECK(find != _unlive_map.end());
   329→                    find->second->is_removed = true;
   330→                    _unlive_map.erase(find);
   331→                }
   332→                SCHECK_EQ(1u, _added_set.erase(server_address));
   333→            }
   334→        }
   335→    }
   336→    // print log
   337→    for (RemoveResultMap::iterator it = remove_results.begin();
   338→            it != remove_results.end(); ++it) {
   339→        const std::string& server_address = it->first;
   340→        const RemoveResult& result = it->second;
   341→        if (!result.remove_failed) {
   342→#if defined( LOG )
   343→            LOG(INFO) << "OnAddressRemoved(): remove address succeed: [" << server_address << "]";
   344→#else
   345→            SLOG(INFO, "OnAddressRemoved(): remove address succeed: [%s]", server_address.c_str());
   346→#endif
   347→        }
   348→        else {
   349→#if defined( LOG )
   350→            LOG(ERROR) << "OnAddressRemoved(): remove address failed: [" << server_address << "]"
   351→                       << result.fail_reason;
   352→#else
   353→            SLOG(ERROR, "OnAddressRemoved(): remove address failed: [%s]: %s",
   354→                    server_address.c_str(), result.fail_reason.c_str());
   355→#endif
   356→        }
   357→    }
   358→}
   359→
   360→void DynamicRpcChannelImpl::CallDone(
   361→        const ServerContextPtr& server,
   362→        const RpcControllerImplPtr& cntl)
   363→{
   364→    --_wait_count;
   365→
   366→    if (server) {
   367→        if (cntl->Failed()) {
   368→            server->is_last_request_succeed = false;
   369→            if (server->is_in_live_map) {
   370→                MoveToUnlive(server->server_address, cntl->Reason());
   371→            }
   372→        }
   373→        else {
   374→            server->is_last_request_succeed = true;
   375→        }
   376→    }
   377→}
   378→
   379→void DynamicRpcChannelImpl::AsyncCallback(
   380→        const ServerContextPtr& server,
   381→        const RpcControllerImplPtr& cntl,
   382→        ::google::protobuf::Closure* done)
   383→{
   384→    CallDone(server, cntl);
   385→    done->Run();
   386→}
   387→
   388→RpcErrorCode DynamicRpcChannelImpl::ChooseServer(ServerContextPtr& choosed_server, int try_num)
   389→{
   390→    choosed_server.reset();
   391→    ScopedLocker<LockType> _(_map_lock);
   392→
   393→    // first choose the channel in _live_map with minimal <wait_count,last_request_seq>.
   394→    if (!_live_map.empty()) {
   395→        uint32_t min_wait_count = kuint32max;
   396→        uint64_t min_last_request_seq = kuint64max;
   397→        for (ServerContextMap::const_iterator it = _live_map.begin();
   398→                it != _live_map.end(); ++it) {
   399→            const ServerContextPtr& server = it->second;
   400→            // if channel is not inited, set wait_count as 0.
   401→            uint32_t wait_count = server->is_channel_inited ? server->channel->WaitCount() : 0;
   402→            // compare by <wait_count,last_request_seq>
   403→            if (wait_count < min_wait_count
   404→                    || (wait_count == min_wait_count
   405→                        && server->last_request_seq < min_last_request_seq)) {
   406→                min_wait_count = wait_count;
   407→                min_last_request_seq = server->last_request_seq;
   408→                choosed_server = server;
   409→            }
   410→        }
   411→        if (_options.server_load_capacity > 0 && choosed_server
   412→                && min_wait_count >= _options.server_load_capacity) {
   413→            // all the live servers exceed the load capacity
   414→#if defined( LOG )
   415→            LOG(ERROR) << "ChooseServer(): reached server capacity: try_num=" << try_num
   416→                       << ", live_map_size=" << _live_map.size()
   417→                       << ", min_wait_count=" << min_wait_count
   418→                       << ", load_capacity=" << _options.server_load_capacity;
   419→#else
   420→            SLOG(ERROR, "ChooseServer(): reached server capacity: try_num=%d"
   421→                    ", live_map_size=%u, min_wait_count=%u, load_capacity=%u",
   422→                    try_num, _live_map.size(), min_wait_count,
   423→                    _options.server_load_capacity);
   424→#endif
   425→            choosed_server.reset();
   426→            return RPC_ERROR_SERVER_BUSY;
   427→        }
   428→    }
   429→
   430→    // found in _live_map, return it.
   431→    if (choosed_server) {
   432→        return RPC_SUCCESS;
   433→    }
   434→
   435→    // then choose the channel in _unlive_map with minimal last_request_seq,
   436→    // and prefer channel with last_request_succeed=true.
   437→    if (!_unlive_map.empty()) {
   438→        bool last_request_succeed = false;
   439→        uint64_t min_last_request_seq = kuint64max;
   440→        for (ServerContextMap::const_iterator it = _unlive_map.begin();
   441→                it != _unlive_map.end(); ++it) {
   442→            const ServerContextPtr& server = it->second;
   443→            if (last_request_succeed) {
   444→                if (server->is_last_request_succeed) {
   445→                    if (server->last_request_seq < min_last_request_seq) {
   446→                        min_last_request_seq = server->last_request_seq;
   447→                        choosed_server = server;
   448→                    }
   449→                }
   450→            }
   451→            else { // !last_request_succeed
   452→                if (server->is_last_request_succeed) {
   453→                    last_request_succeed = true;
   454→                    min_last_request_seq = server->last_request_seq;
   455→                    choosed_server = server;
   456→                }
   457→                else { // !server->is_last_request_succeed
   458→                    if (server->last_request_seq < min_last_request_seq) {
   459→                        min_last_request_seq = server->last_request_seq;
   460→                        choosed_server = server;
   461→                    }
   462→                }
   463→            }
   464→        }
   465→    }
   466→    
   467→    if (choosed_server) {
   468→        return RPC_SUCCESS;
   469→    }
   470→    else {
   471→#if defined( LOG )
   472→        LOG(ERROR) << "ChooseServer(): no server choosed: try_num=" << try_num
   473→                   << ", live_map_size=" << _live_map.size()
   474→                   << ", unlive_map_size=" << _unlive_map.size();
   475→#else
   476→        SLOG(ERROR, "ChooseServer(): no server choosed: try_num=%d"
   477→                ", live_map_size=%u, unlive_map_size=%u",
   478→                try_num, _live_map.size(), _unlive_map.size());
   479→#endif
   480→        return RPC_ERROR_SERVER_UNAVAILABLE;
   481→    }
   482→}
   483→
   484→void DynamicRpcChannelImpl::MoveToUnlive(
   485→        const std::string& server_address,
   486→        const std::string& reason)
   487→{
   488→    bool succeed = false;
   489→    {
   490→        ScopedLocker<LockType> _(_map_lock);
   491→        ServerContextMap::iterator find = _live_map.find(server_address);
   492→        if (find != _live_map.end()) {
   493→            ServerContextPtr server = find->second;
   494→            _live_map.erase(find);
   495→            server->is_in_live_map = false;
   496→            _unlive_map[server_address] = server;
   497→            succeed = true;
   498→        }
   499→    }
   500→    if (succeed) {
   501→#if defined( LOG )
   502→        LOG(INFO) << "MoveToUnlive(): [" << server_address << "]: " << reason;
   503→#else
   504→        SLOG(INFO, "MoveToUnlive(): [%s]: %s", server_address.c_str(), reason.c_str());
   505→#endif
   506→    }
   507→}
   508→
   509→void DynamicRpcChannelImpl::MoveToLive(const std::string& server_address)
   510→{
   511→    bool succeed = false;
   512→    {
   513→        ScopedLocker<LockType> _(_map_lock);
   514→        ServerContextMap::iterator find = _unlive_map.find(server_address);
   515→        if (find != _unlive_map.end()) {
   516→            ServerContextPtr server = find->second;
   517→            _unlive_map.erase(find);
   518→            server->is_in_live_map = true;
   519→            _live_map[server_address] = server;
   520→            succeed = true;
   521→        }
   522→    }
   523→    if (succeed) {
   524→#if defined( LOG )
   525→        LOG(INFO) << "MoveToLive(): [" << server_address << "]";
   526→#else
   527→        SLOG(INFO, "MoveToLive(): [%s]", server_address.c_str());
   528→#endif
   529→    }
   530→}
   531→
   532→void DynamicRpcChannelImpl::TimerDetect(
   533→        TimeoutManager::Id /*id*/,
   534→        TimeoutManager::Type type)
   535→{
   536→    if (type == TimeoutManager::ERASED || type == TimeoutManager::CLEARED) {
   537→        // ignore ERASED and CLEARED event
   538→        return;
   539→    }
   540→
   541→    ScopedLocker<LockType> _(_detect_lock);
   542→    if (_is_detect_disabled) {
   543→        // disabled
   544→        return;
   545→    }
   546→
   547→    ServerContextMap detect_map;
   548→    {
   549→        ScopedLocker<LockType> _(_map_lock);
   550→        detect_map = _unlive_map;
   551→    }
   552→    for (ServerContextMap::iterator it = detect_map.begin();
   553→            it != detect_map.end(); ++it) {
   554→        ServerContextPtr& server = it->second;
   555→        if (server->is_removed || server->is_in_live_map) {
   556→            // ignore
   557→            continue;
   558→        }
   559→        // init builtin service.
   560→        if (!server->InitBuiltinService(_options)) {
   561→            // init failed
   562→#if defined( LOG )
   563→            LOG(WARNING) << "TimerDetect(): init builtin service failed: ["
   564→                         << server->server_address << "]";
   565→#else
   566→            SLOG(WARNING, "TimerDetect(): init builtin service failed: [%s]",
   567→                    server->server_address.c_str());
   568→#endif
   569→            continue;
   570→        }
   571→        SCHECK(server->builtin_service);
   572→        // async detect
   573→        RpcController* cntl = new RpcController();
   574→        cntl->SetTimeout(kDetectTimeout);
   575→        builtin::HealthRequest* request = new builtin::HealthRequest();
   576→        builtin::HealthResponse* response = new builtin::HealthResponse();
   577→        ::google::protobuf::Closure* done = ::sofa::pbrpc::NewClosure(shared_from_this(),
   578→                    &DynamicRpcChannelImpl::DetectCallback, server, cntl, request, response);
   579→        server->builtin_service->Health(cntl, request, response, done);
   580→    }
   581→}
   582→
   583→void DynamicRpcChannelImpl::DetectCallback(
   584→        const ServerContextPtr& server,
   585→        RpcController* cntl,
   586→        builtin::HealthRequest* request,
   587→        builtin::HealthResponse* response)
   588→{
   589→    if (!server->is_removed && !server->is_in_live_map
   590→            && !cntl->Failed() && response->health() == "OK") {
   591→        // detect succeed
   592→        MoveToLive(server->server_address);
   593→    }
   594→    delete request;
   595→    delete response;
   596→    delete cntl;
   597→}
   598→
   599→DynamicRpcChannelImpl::ServerContext::ServerContext(const std::string& server_address_)
   600→{
   601→    server_address = server_address_;
   602→    is_last_request_succeed = true;
   603→    is_in_live_map = true;
   604→    is_removed = false;
   605→    is_channel_inited = false;
   606→    is_builtin_service_inited = false;
   607→    last_request_seq = 0;
   608→}
   609→
   610→DynamicRpcChannelImpl::ServerContext::~ServerContext()
   611→{
   612→}
   613→
   614→bool DynamicRpcChannelImpl::ServerContext::InitChannel(
   615→        const RpcClientImplPtr& client_impl,
   616→        const RpcChannelOptions& options)
   617→{
   618→    if (is_channel_inited) {
   619→        return true;
   620→    }
   621→    ScopedLocker<LockType> _(channel_init_lock);
   622→    if (is_channel_inited) {
   623→        // double check
   624→        return true;
   625→    }
   626→    SCHECK(!channel);
   627→    channel.reset(new SimpleRpcChannelImpl(client_impl, server_address, options));
   628→    if (!channel->Init()) {
   629→        // init failed
   630→#if defined( LOG )
   631→        LOG(ERROR) << "InitChannel(): init simple channel failed: [" << server_address << "]";
   632→#else
   633→        SLOG(ERROR, "InitChannel(): init simple channel failed: [%s]", server_address.c_str());
   634→#endif
   635→        channel.reset();
   636→        return false;
   637→    }
   638→#if defined( LOG )
   639→    LOG(INFO) << "InitChannel(): init simple channel succeed: [" << server_address << "]";
   640→#else
   641→    SLOG(INFO, "InitChannel(): init simple channel succeed: [%s]", server_address.c_str());
   642→#endif
   643→    is_channel_inited = true;
   644→    return true;
   645→}
   646→
   647→bool DynamicRpcChannelImpl::ServerContext::InitBuiltinService(const RpcChannelOptions& /*options*/)
   648→{
   649→    if (is_builtin_service_inited) {
   650→        return true;
   651→    }
   652→    ScopedLocker<LockType> _(builtin_service_init_lock);
   653→    if (is_builtin_service_inited) {
   654→        // double check
   655→        return true;
   656→    }
   657→    if (!channel) {
   658→        // no channel available
   659→        return false;
   660→    }
   661→    builtin_service.reset(new builtin::BuiltinService_Stub(channel.get()));
   662→#if defined( LOG )
   663→    LOG(INFO) << "InitBuiltinService(): init succeed: [" << server_address << "]";
   664→#else
   665→    SLOG(INFO, "InitBuiltinService(): init succeed: [%s]", server_address.c_str());
   666→#endif
   667→    is_builtin_service_inited = true;
   668→    return true;
   669→}
   670→
   671→} // namespace pbrpc
   672→} // namespace sofa
